import { describe, expect, it } from "vitest";
import { orderTotalCents } from "../src/money.js";

describe("orderTotalCents", () => {
  it("sums lines with no discount", () => {
    expect(orderTotalCents([{ unitCents: 500, qty: 2 }], 0)).toBe(1000);
  });
});

input.command:
node -e '
function perLine(lines,d){let t=0;for(const l of lines)t+=Math.round(l.unitCents*l.qty*(1-d/100));return t;}
function once(lines,d){let s=0;for(const l of lines)s+=l.unitCents*l.qty;return Math.round(s*(1-d/100));}
const lines=[{unitCents:500,qty:1},{unitCents:500,qty:1}];
console.log("perLine",perLine(lines,10.1),"once",once(lines,10.1));
'

input.old_string:
  it("sums lines with no discount", () => {
    expect(orderTotalCents([{ unitCents: 500, qty: 2 }], 0)).toBe(1000);
  });
});

input.new_string:
  it("sums lines with no discount", () => {
    expect(orderTotalCents([{ unitCents: 500, qty: 2 }], 0)).toBe(1000);
  });

  it("applies the discount to the subtotal and rounds once", () => {
    // Two $5.00 lines, 10.1% off. Exact subtotal discount:
    // 1000 * 0.899 = 899 -> $8.99. Rounding each line separately gives
    // round(449.5) * 2 = 900 -> $9.00, the reported one-cent drift.
    expect(orderTotalCents([{ unitCents: 500, qty: 1 }, { unitCents: 500, qty: 1 }], 10.1)).toBe(899);
  });
});

